package com.example.oidc.service;

import org.springframework.stereotype.Component;

import java.security.SecureRandom;
import java.util.Base64;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.ConcurrentMap;

@Component
public class StateManager {

    private final ConcurrentMap<String, Long> stateStore = new ConcurrentHashMap<>();
    private final SecureRandom secureRandom = new SecureRandom();
    private static final long STATE_EXPIRY_MS = 600_000; // 10 minutes

    public String generateState() {
        byte[] bytes = new byte[32];
        secureRandom.nextBytes(bytes);
        String state = Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
        stateStore.put(state, System.currentTimeMillis());
        cleanupExpiredStates();
        return state;
    }

    public String generateNonce() {
        byte[] bytes = new byte[32];
        secureRandom.nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes);
    }

    public boolean validateAndConsumeState(String state) {
        if (state == null) return false;
        Long timestamp = stateStore.remove(state);
        if (timestamp == null) return false;
        return (System.currentTimeMillis() - timestamp) < STATE_EXPIRY_MS;
    }

    private void cleanupExpiredStates() {
        long now = System.currentTimeMillis();
        stateStore.entrySet().removeIf(entry -> (now - entry.getValue()) > STATE_EXPIRY_MS);
    }
}

