package com.example.oidc.service;

import com.example.oidc.config.OidcProviderConfig;
import com.example.oidc.model.OidcTokenResponse;
import com.nimbusds.jose.JWSAlgorithm;
import com.nimbusds.jose.jwk.source.JWKSource;
import com.nimbusds.jose.jwk.source.RemoteJWKSet;
import com.nimbusds.jose.proc.JWSKeySelector;
import com.nimbusds.jose.proc.JWSVerificationKeySelector;
import com.nimbusds.jose.proc.SecurityContext;
import com.nimbusds.jwt.JWTClaimsSet;
import com.nimbusds.jwt.proc.ConfigurableJWTProcessor;
import com.nimbusds.jwt.proc.DefaultJWTClaimsVerifier;
import com.nimbusds.jwt.proc.DefaultJWTProcessor;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.*;
import org.springframework.stereotype.Service;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.MultiValueMap;
import org.springframework.web.client.RestClientException;
import org.springframework.web.client.RestTemplate;

import java.net.MalformedURLException;
import java.net.URI;
import java.net.URL;
import java.util.Arrays;
import java.util.Date;
import java.util.HashSet;

@Service
public class TokenService {

    private static final Logger logger = LoggerFactory.getLogger(TokenService.class);

    private final OidcProviderConfig providerConfig;
    private final RestTemplate restTemplate;
    private final ConfigurableJWTProcessor<SecurityContext> jwtProcessor;

    public TokenService(OidcProviderConfig providerConfig) {
        this.providerConfig = providerConfig;
        this.restTemplate = new RestTemplate();
        this.jwtProcessor = createJwtProcessor();
    }

    private ConfigurableJWTProcessor<SecurityContext> createJwtProcessor() {
        ConfigurableJWTProcessor<SecurityContext> processor = new DefaultJWTProcessor<>();

        try {
            if (providerConfig.getJwkSetUri() != null && !providerConfig.getJwkSetUri().isEmpty()) {
                JWKSource<SecurityContext> keySource = new RemoteJWKSet<>(
                        new URL(providerConfig.getJwkSetUri()));
                JWSKeySelector<SecurityContext> keySelector = new JWSVerificationKeySelector<>(
                        JWSAlgorithm.RS256, keySource);
                processor.setJWSKeySelector(keySelector);

                DefaultJWTClaimsVerifier<SecurityContext> claimsVerifier = new DefaultJWTClaimsVerifier<>(
                        new JWTClaimsSet.Builder()
                                .issuer(providerConfig.getIssuer())
                                .build(),
                        new HashSet<>(Arrays.asList("sub", "iat", "exp", "iss"))
                );
                processor.setJWTClaimsVerifier(claimsVerifier);
            }
        } catch (MalformedURLException e) {
            logger.error("Invalid JWK Set URI: {}", providerConfig.getJwkSetUri(), e);
        }

        return processor;
    }

    public OidcTokenResponse exchangeAuthorizationCode(String code, String codeVerifier) {
        validateTokenEndpoint(providerConfig.getTokenUri());

        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);
        headers.setAccept(Arrays.asList(MediaType.APPLICATION_JSON));

        MultiValueMap<String, String> params = new LinkedMultiValueMap<>();
        params.add("grant_type", "authorization_code");
        params.add("code", code);
        params.add("redirect_uri", providerConfig.getRedirectUri());
        params.add("client_id", providerConfig.getClientId());
        params.add("client_secret", providerConfig.getClientSecret());

        if (codeVerifier != null && !codeVerifier.isEmpty()) {
            params.add("code_verifier", codeVerifier);
        }

        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(params, headers);

        try {
            ResponseEntity<OidcTokenResponse> response = restTemplate.exchange(
                    providerConfig.getTokenUri(),
                    HttpMethod.POST,
                    request,
                    OidcTokenResponse.class
            );

            if (response.getStatusCode() == HttpStatus.OK && response.getBody() != null) {
                logger.info("Successfully exchanged authorization code for tokens");
                return response.getBody();
            } else {
                logger.error("Token exchange failed with status: {}", response.getStatusCode());
                throw new RuntimeException("Token exchange failed with status: " + response.getStatusCode());
            }
        } catch (RestClientException e) {
            logger.error("Error during token exchange", e);
            throw new RuntimeException("Failed to exchange authorization code for tokens", e);
        }
    }

    public JWTClaimsSet validateAndParseIdToken(String idToken, String expectedNonce) {
        try {
            JWTClaimsSet claims = jwtProcessor.process(idToken, null);

            // Validate audience
            if (!claims.getAudience().contains(providerConfig.getClientId())) {
                throw new SecurityException("ID token audience does not match client ID");
            }

            // Validate expiration
            Date expiration = claims.getExpirationTime();
            if (expiration != null && new Date().after(expiration)) {
                throw new SecurityException("ID token has expired");
            }

            // Validate nonce if provided
            if (expectedNonce != null) {
                String tokenNonce = (String) claims.getClaim("nonce");
                if (!expectedNonce.equals(tokenNonce)) {
                    throw new SecurityException("ID token nonce does not match expected nonce");
                }
            }

            // Validate issuer
            if (!providerConfig.getIssuer().equals(claims.getIssuer())) {
                throw new SecurityException("ID token issuer does not match expected issuer");
            }

            logger.info("ID token validated successfully for subject: {}", claims.getSubject());
            return claims;

        } catch (Exception e) {
            logger.error("ID token validation failed", e);
            throw new RuntimeException("Failed to validate ID token", e);
        }
    }

    public OidcTokenResponse refreshAccessToken(String refreshToken) {
        validateTokenEndpoint(providerConfig.getTokenUri());

        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);

        MultiValueMap<String, String> params = new LinkedMultiValueMap<>();
        params.add("grant_type", "refresh_token");
        params.add("refresh_token", refreshToken);
        params.add("client_id", providerConfig.getClientId());
        params.add("client_secret", providerConfig.getClientSecret());

        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(params, headers);

        try {
            ResponseEntity<OidcTokenResponse> response = restTemplate.exchange(
                    providerConfig.getTokenUri(),
                    HttpMethod.POST,
                    request,
                    OidcTokenResponse.class
            );

            if (response.getStatusCode() == HttpStatus.OK && response.getBody() != null) {
                logger.info("Successfully refreshed access token");
                return response.getBody();
            } else {
                throw new RuntimeException("Token refresh failed with status: " + response.getStatusCode());
            }
        } catch (RestClientException e) {
            logger.error("Error during token refresh", e);
            throw new RuntimeException("Failed to refresh access token", e);
        }
    }

    private void validateTokenEndpoint(String tokenUri) {
        if (tokenUri == null || tokenUri.isEmpty()) {
            throw new IllegalStateException("Token endpoint URI is not configured");
        }

        try {
            URI uri = URI.create(tokenUri);
            if (!"https".equalsIgnoreCase(uri.getScheme())) {
                logger.warn("Token endpoint is not using HTTPS: {}. This is insecure in production!", tokenUri);
            }
        } catch (IllegalArgumentException e) {
            throw new IllegalStateException("Invalid token endpoint URI: " + tokenUri, e);
        }
    }
}

