package com.example.oidc.service;

import com.example.oidc.config.OidcProviderConfig;
import com.example.oidc.model.OidcUserInfo;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.*;
import org.springframework.stereotype.Service;
import org.springframework.web.client.RestClientException;
import org.springframework.web.client.RestTemplate;

import java.util.Collections;
import java.util.Map;

@Service
public class UserInfoService {

    private static final Logger logger = LoggerFactory.getLogger(UserInfoService.class);

    private final OidcProviderConfig providerConfig;
    private final RestTemplate restTemplate;

    public UserInfoService(OidcProviderConfig providerConfig) {
        this.providerConfig = providerConfig;
        this.restTemplate = new RestTemplate();
    }

    @SuppressWarnings("unchecked")
    public OidcUserInfo fetchUserInfo(String accessToken) {
        if (providerConfig.getUserInfoUri() == null || providerConfig.getUserInfoUri().isEmpty()) {
            logger.warn("UserInfo endpoint is not configured");
            return null;
        }

        HttpHeaders headers = new HttpHeaders();
        headers.setBearerAuth(accessToken);
        headers.setAccept(Collections.singletonList(MediaType.APPLICATION_JSON));

        HttpEntity<Void> request = new HttpEntity<>(headers);

        try {
            ResponseEntity<Map> response = restTemplate.exchange(
                    providerConfig.getUserInfoUri(),
                    HttpMethod.GET,
                    request,
                    Map.class
            );

            if (response.getStatusCode() == HttpStatus.OK && response.getBody() != null) {
                Map<String, Object> claims = response.getBody();
                return mapToUserInfo(claims);
            } else {
                logger.error("UserInfo request failed with status: {}", response.getStatusCode());
                return null;
            }
        } catch (RestClientException e) {
            logger.error("Error fetching user info", e);
            return null;
        }
    }

    private OidcUserInfo mapToUserInfo(Map<String, Object> claims) {
        OidcUserInfo userInfo = new OidcUserInfo();
        userInfo.setSubject(getStringClaim(claims, "sub"));
        userInfo.setEmail(getStringClaim(claims, "email"));
        userInfo.setEmailVerified(getBooleanClaim(claims, "email_verified"));
        userInfo.setName(getStringClaim(claims, "name"));
        userInfo.setGivenName(getStringClaim(claims, "given_name"));
        userInfo.setFamilyName(getStringClaim(claims, "family_name"));
        userInfo.setPreferredUsername(getStringClaim(claims, "preferred_username"));
        userInfo.setPicture(getStringClaim(claims, "picture"));
        userInfo.setLocale(getStringClaim(claims, "locale"));
        userInfo.setAdditionalClaims(claims);
        return userInfo;
    }

    private String getStringClaim(Map<String, Object> claims, String key) {
        Object value = claims.get(key);
        return value != null ? value.toString() : null;
    }

    private boolean getBooleanClaim(Map<String, Object> claims, String key) {
        Object value = claims.get(key);
        if (value instanceof Boolean) return (Boolean) value;
        if (value instanceof String) return Boolean.parseBoolean((String) value);
        return false;
    }
}

