package com.example.oidc.service;

import com.example.oidc.model.OidcTokenResponse;
import com.example.oidc.model.OidcUserInfo;
import com.example.oidc.model.UserSession;
import com.nimbusds.jwt.JWTClaimsSet;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.stereotype.Service;

import jakarta.servlet.http.HttpSession;
import java.time.Instant;
import java.util.Collections;
import java.util.List;

@Service
public class SessionService {

    private static final Logger logger = LoggerFactory.getLogger(SessionService.class);
    private static final String USER_SESSION_KEY = "USER_SESSION";

    public UserSession createSession(HttpSession httpSession, JWTClaimsSet idTokenClaims,
                                      OidcTokenResponse tokenResponse, OidcUserInfo userInfo) {
        UserSession session = new UserSession();

        // Populate from ID token claims
        session.setSubject(idTokenClaims.getSubject());

        try {
            session.setEmail((String) idTokenClaims.getClaim("email"));
            session.setName((String) idTokenClaims.getClaim("name"));
            session.setPreferredUsername((String) idTokenClaims.getClaim("preferred_username"));
            session.setPicture((String) idTokenClaims.getClaim("picture"));
        } catch (Exception e) {
            logger.warn("Error extracting claims from ID token", e);
        }

        // Override with UserInfo if available (UserInfo is more authoritative)
        if (userInfo != null) {
            if (userInfo.getEmail() != null) session.setEmail(userInfo.getEmail());
            if (userInfo.getName() != null) session.setName(userInfo.getName());
            if (userInfo.getPreferredUsername() != null) session.setPreferredUsername(userInfo.getPreferredUsername());
            if (userInfo.getPicture() != null) session.setPicture(userInfo.getPicture());
        }

        // Store tokens
        session.setAccessToken(tokenResponse.getAccessToken());
        session.setRefreshToken(tokenResponse.getRefreshToken());
        session.setIdToken(tokenResponse.getIdToken());

        if (tokenResponse.getExpiresIn() != null) {
            session.setTokenExpiry(Instant.now().plusSeconds(tokenResponse.getExpiresIn()));
        }

        // Store in HTTP session
        httpSession.setAttribute(USER_SESSION_KEY, session);

        // Set Spring Security context
        String displayName = session.getName() != null ? session.getName() : session.getSubject();
        List<SimpleGrantedAuthority> authorities = Collections.singletonList(
                new SimpleGrantedAuthority("ROLE_USER"));
        UsernamePasswordAuthenticationToken authentication =
                new UsernamePasswordAuthenticationToken(displayName, null, authorities);
        SecurityContextHolder.getContext().setAuthentication(authentication);

        logger.info("Created user session for subject: {}, name: {}", session.getSubject(), session.getName());
        return session;
    }

    public UserSession getSession(HttpSession httpSession) {
        return (UserSession) httpSession.getAttribute(USER_SESSION_KEY);
    }

    public void invalidateSession(HttpSession httpSession) {
        httpSession.removeAttribute(USER_SESSION_KEY);
        SecurityContextHolder.clearContext();
        httpSession.invalidate();
        logger.info("User session invalidated");
    }
}

