package com.example.oidc.controller;

import com.example.oidc.config.OidcProviderConfig;
import com.example.oidc.model.OidcTokenResponse;
import com.example.oidc.model.OidcUserInfo;
import com.example.oidc.model.UserSession;
import com.example.oidc.service.*;
import com.nimbusds.jwt.JWTClaimsSet;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.util.UriComponentsBuilder;

import jakarta.servlet.http.HttpSession;

@Controller
public class AuthController {

    private static final Logger logger = LoggerFactory.getLogger(AuthController.class);

    private final OidcProviderConfig providerConfig;
    private final TokenService tokenService;
    private final UserInfoService userInfoService;
    private final SessionService sessionService;
    private final StateManager stateManager;

    public AuthController(OidcProviderConfig providerConfig, TokenService tokenService,
                          UserInfoService userInfoService, SessionService sessionService,
                          StateManager stateManager) {
        this.providerConfig = providerConfig;
        this.tokenService = tokenService;
        this.userInfoService = userInfoService;
        this.sessionService = sessionService;
        this.stateManager = stateManager;
    }

    @GetMapping("/")
    public String home(HttpSession httpSession, Model model) {
        UserSession session = sessionService.getSession(httpSession);
        if (session != null) {
            model.addAttribute("user", session);
            model.addAttribute("authenticated", true);
        } else {
            model.addAttribute("authenticated", false);
        }
        return "home";
    }

    @GetMapping("/login")
    public String login(HttpSession httpSession) {
        String state = stateManager.generateState();
        String nonce = stateManager.generateNonce();

        // Generate PKCE code verifier and challenge
        String codeVerifier = PkceUtil.generateCodeVerifier();
        String codeChallenge = PkceUtil.generateCodeChallenge(codeVerifier);

        // Store state, nonce, and code verifier in session
        httpSession.setAttribute("oidc_state", state);
        httpSession.setAttribute("oidc_nonce", nonce);
        httpSession.setAttribute("oidc_code_verifier", codeVerifier);

        String authorizationUrl = UriComponentsBuilder.fromUriString(providerConfig.getAuthorizationUri())
                .queryParam("response_type", "code")
                .queryParam("client_id", providerConfig.getClientId())
                .queryParam("redirect_uri", providerConfig.getRedirectUri())
                .queryParam("scope", providerConfig.getScope())
                .queryParam("state", state)
                .queryParam("nonce", nonce)
                .queryParam("code_challenge", codeChallenge)
                .queryParam("code_challenge_method", "S256")
                .build()
                .toUriString();

        logger.info("Redirecting to OIDC provider for authentication");
        return "redirect:" + authorizationUrl;
    }

    @GetMapping("/callback")
    public String callback(@RequestParam(required = false) String code,
                           @RequestParam(required = false) String state,
                           @RequestParam(required = false) String error,
                           @RequestParam(name = "error_description", required = false) String errorDescription,
                           HttpSession httpSession,
                           Model model) {

        // Handle error response from provider
        if (error != null) {
            logger.error("OIDC authentication error: {} - {}", error, errorDescription);
            model.addAttribute("error", error);
            model.addAttribute("errorDescription", errorDescription);
            return "error";
        }

        // Validate authorization code is present
        if (code == null || code.isEmpty()) {
            logger.error("No authorization code received");
            model.addAttribute("error", "No authorization code received");
            return "error";
        }

        // Validate state parameter
        String expectedState = (String) httpSession.getAttribute("oidc_state");
        if (!stateManager.validateAndConsumeState(state) || !state.equals(expectedState)) {
            logger.error("Invalid state parameter - possible CSRF attack");
            model.addAttribute("error", "Invalid state parameter");
            return "error";
        }

        String nonce = (String) httpSession.getAttribute("oidc_nonce");
        String codeVerifier = (String) httpSession.getAttribute("oidc_code_verifier");

        // Clean up session attributes
        httpSession.removeAttribute("oidc_state");
        httpSession.removeAttribute("oidc_nonce");
        httpSession.removeAttribute("oidc_code_verifier");

        try {
            // Exchange authorization code for tokens
            OidcTokenResponse tokenResponse = tokenService.exchangeAuthorizationCode(code, codeVerifier);

            // Validate and parse ID token
            JWTClaimsSet idTokenClaims = tokenService.validateAndParseIdToken(
                    tokenResponse.getIdToken(), nonce);

            // Fetch additional user info
            OidcUserInfo userInfo = null;
            if (tokenResponse.getAccessToken() != null) {
                userInfo = userInfoService.fetchUserInfo(tokenResponse.getAccessToken());
            }

            // Create user session
            UserSession userSession = sessionService.createSession(
                    httpSession, idTokenClaims, tokenResponse, userInfo);

            logger.info("User authenticated successfully: {}", userSession.getSubject());
            return "redirect:/dashboard";

        } catch (Exception e) {
            logger.error("Authentication failed", e);
            model.addAttribute("error", "Authentication failed: " + e.getMessage());
            return "error";
        }
    }

    @GetMapping("/dashboard")
    public String dashboard(HttpSession httpSession, Model model) {
        UserSession session = sessionService.getSession(httpSession);
        if (session == null) {
            return "redirect:/login";
        }

        // Check if token needs refresh
        if (session.isTokenExpired() && session.getRefreshToken() != null) {
            try {
                OidcTokenResponse refreshedTokens = tokenService.refreshAccessToken(session.getRefreshToken());
                session.setAccessToken(refreshedTokens.getAccessToken());
                if (refreshedTokens.getRefreshToken() != null) {
                    session.setRefreshToken(refreshedTokens.getRefreshToken());
                }
                if (refreshedTokens.getExpiresIn() != null) {
                    session.setTokenExpiry(java.time.Instant.now().plusSeconds(refreshedTokens.getExpiresIn()));
                }
                logger.info("Access token refreshed for user: {}", session.getSubject());
            } catch (Exception e) {
                logger.error("Token refresh failed, redirecting to login", e);
                sessionService.invalidateSession(httpSession);
                return "redirect:/login";
            }
        }

        model.addAttribute("user", session);
        return "dashboard";
    }

    @GetMapping("/logout")
    public String logout(HttpSession httpSession) {
        UserSession session = sessionService.getSession(httpSession);
        String idToken = session != null ? session.getIdToken() : null;

        sessionService.invalidateSession(httpSession);

        // Redirect to OIDC provider's end session endpoint if configured
        if (providerConfig.getEndSessionEndpoint() != null && !providerConfig.getEndSessionEndpoint().isEmpty()) {
            UriComponentsBuilder builder = UriComponentsBuilder
                    .fromUriString(providerConfig.getEndSessionEndpoint())
                    .queryParam("post_logout_redirect_uri", providerConfig.getRedirectUri().replace("/callback", "/"));

            if (idToken != null) {
                builder.queryParam("id_token_hint", idToken);
            }

            return "redirect:" + builder.build().toUriString();
        }

        return "redirect:/";
    }
}

