package com.example.oidc.controller;

import jakarta.servlet.*;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.core.annotation.Order;
import org.springframework.stereotype.Component;

import java.io.IOException;

/**
 * Filter to prevent direct access to the OIDC token endpoint proxy.
 * This ensures that token exchange only happens through the legitimate
 * authorization code callback flow and blocks any external or forged
 * requests to the token endpoint.
 */
@Component
@Order(1)
public class TokenEndpointProtectionFilter implements Filter {

    private static final Logger logger = LoggerFactory.getLogger(TokenEndpointProtectionFilter.class);

    @Override
    public void doFilter(ServletRequest request, ServletResponse response, FilterChain chain)
            throws IOException, ServletException {

        HttpServletRequest httpRequest = (HttpServletRequest) request;
        HttpServletResponse httpResponse = (HttpServletResponse) response;

        String requestUri = httpRequest.getRequestURI();

        // Block any direct access to token-related endpoints
        if (isTokenEndpointRequest(requestUri)) {
            logger.warn("Blocked direct access attempt to token endpoint: {} from IP: {}",
                    requestUri, httpRequest.getRemoteAddr());
            httpResponse.setStatus(HttpServletResponse.SC_FORBIDDEN);
            httpResponse.setContentType("application/json");
            httpResponse.getWriter().write("{\"error\":\"access_denied\",\"error_description\":\"Direct access to token endpoint is not allowed\"}");
            return;
        }

        chain.doFilter(request, response);
    }

    private boolean isTokenEndpointRequest(String uri) {
        if (uri == null) return false;
        String normalizedUri = uri.toLowerCase();
        return normalizedUri.equals("/token") ||
               normalizedUri.equals("/oauth/token") ||
               normalizedUri.equals("/oauth2/token") ||
               normalizedUri.equals("/api/token") ||
               normalizedUri.startsWith("/token/") ||
               normalizedUri.equals("/oidc/token");
    }
}

