package com.example.oidc.controller;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.util.Map;

/**
 * Explicitly blocks all HTTP methods on token-related paths.
 * This acts as a secondary defense layer alongside the filter.
 */
@RestController
public class TokenEndpointController {

    private static final Logger logger = LoggerFactory.getLogger(TokenEndpointController.class);

    @RequestMapping(value = {"/token", "/oauth/token", "/oauth2/token", "/api/token", "/oidc/token"},
                    method = {RequestMethod.GET, RequestMethod.POST, RequestMethod.PUT,
                              RequestMethod.DELETE, RequestMethod.PATCH})
    public ResponseEntity<Map<String, String>> blockTokenEndpoint() {
        logger.warn("Attempted direct access to token endpoint blocked by controller");
        return ResponseEntity.status(HttpStatus.FORBIDDEN)
                .body(Map.of(
                        "error", "access_denied",
                        "error_description", "Direct access to token endpoint is not permitted. " +
                                "Token exchange is handled internally through the authorization code flow."
                ));
    }
}

